System.register([],function(e,t){return{setters:[],execute:function(){e("n",[{id:"essay",icon:"fa-headphones-simple",label:"范文精读"},{id:"quickfire",icon:"fa-sitemap",label:"导图转译"},{id:"grammar",icon:"fa-puzzle-piece",label:"高级句式"}]),e("r",{basketball:{id:"basketball",title:"Basketball",icon:"fa-basketball",color:"from-orange-500 to-red-600",fullText:"When it comes to hobbies, I firmly believe that shooting hoops is the absolute best way to spend my free time. To begin with, breaking a sweat on the court keeps me fit and helps me blow off steam after a long day of studying. More importantly, basketball is a team sport. It teaches me how to communicate effectively and have each other's backs. For instance, whenever we win a tough match by passing the ball selflessly, I feel absolutely on top of the world. Ultimately, this is exactly why basketball makes me a much stronger and better person.",chunks:[{text:"When it comes to hobbies, I firmly believe that ",type:"hook"},{text:"shooting hoops ",type:"native"},{text:"is the absolute best way to spend my free time. ",type:"normal"},{text:"To begin with, ",type:"connector"},{text:"breaking a sweat ",type:"native"},{text:"on the court keeps me fit and helps me ",type:"normal"},{text:"blow off steam ",type:"native"},{text:"after a long day of studying. ",type:"normal"},{text:"More importantly, ",type:"connector"},{text:"basketball is a team sport. It teaches me how to communicate effectively and ",type:"normal"},{text:"have each other's backs. ",type:"native"},{text:"For instance, ",type:"connector"},{text:"whenever we win a tough match by passing the ball selflessly, I feel absolutely ",type:"normal"},{text:"on top of the world. ",type:"native"},{text:"Ultimately, this is exactly why ",type:"hook"},{text:"basketball makes me a much stronger and better person.",type:"normal"}],explanations:{"shooting hoops ":{tag:"地道表达",zh:"投篮，打篮球。比单纯说 play basketball 更地道生动。"},"breaking a sweat ":{tag:"高级动作",zh:"挥洒汗水，大汗淋漓地运动。"},"blow off steam ":{tag:"俚语/地道",zh:"释放压力，宣泄情绪（就像烧开水放出蒸汽一样）。"},"have each other's backs. ":{tag:"高分短语",zh:"互相支持，做彼此的后盾。"},"on top of the world. ":{tag:"高级情绪表达",zh:"极度开心，感觉站在世界之巅。"},"When it comes to hobbies, I firmly believe that ":{tag:"高级开场",zh:"一说到爱好，我坚信..."},"Ultimately, this is exactly why ":{tag:"完美收尾",zh:"归根结底，这正是为什么..."}},audioQuiz:[{audio:"shooting hoops",ans:0,options:["打篮球/投篮","突破防守","团队合作","释放压力"]},{audio:"blow off steam",ans:2,options:["挥洒汗水","大发雷霆","释放压力","互相支持"]},{audio:"have each other's backs",ans:1,options:["背对背防守","互相支持","背信弃义","退居幕后"]},{audio:"breaking a sweat",ans:3,options:["打破纪录","受伤休息","突破极限","挥洒汗水"]},{audio:"on top of the world",ans:0,options:["极度开心/自豪","世界第一","环游世界","压力山大"]}],quickFire:[{zh:"打篮球/投篮",ans:1,options:["Play balls","Shooting hoops","Breaking a sweat","On top"]},{zh:"挥洒汗水",ans:0,options:["Breaking a sweat","Blowing steam","Working hard","Sweating out"]},{zh:"释放压力",ans:2,options:["Release pressure","Have backs","Blow off steam","Feel good"]},{zh:"互相支持（做后盾）",ans:3,options:["Support friends","Team sport","Pass ball","Have each other's backs"]},{zh:"极度开心/自豪",ans:1,options:["Very happy","On top of the world","Shooting hoops","Blow off steam"]}],mindMap:[{phase:"P",title:"Point 观点",zh:"最爱打篮球",zhSub:"打发时间的最佳方式",en:"When it comes to hobbies, I firmly believe that shooting hoops is the absolute best way...",highlight:["shooting hoops"]},{phase:"E",title:"Explain 解释",zh:"强健身体 + 缓解压力",zhSub:"在球场上挥洒汗水",en:"To begin with, breaking a sweat on the court keeps me fit and helps me blow off steam...",highlight:["breaking a sweat","blow off steam"]},{phase:"A",title:"Analysis 分析",zh:"团队运动教会我沟通与支持",zhSub:"无私传球赢得比赛的成就感",en:"More importantly... teaches me how to communicate effectively and have each other's backs. For instance... feel on top of the world.",highlight:["have each other's backs","on top of the world"]},{phase:"C",title:"Conclusion 总结",zh:"让我变成更好更强的人",zhSub:"这就是为什么它如此重要",en:"Ultimately, this is exactly why basketball makes me a much stronger and better person.",highlight:["Ultimately, this is exactly why"]}]},piano:{id:"piano",title:"Piano",icon:"fa-music",color:"from-blue-500 to-indigo-600",fullText:"When it comes to hobbies, I firmly believe that tickling the ivories is the most wonderful thing in my life. To begin with, playing classical music helps me find my inner peace and relax my mind after a busy day. Furthermore, it takes a lot of patience. For instance, whenever I try to get the hang of a difficult piece, I have to practice it over and over again. This trains my focus. When I finally play it perfectly, the sense of achievement is simply mind-blowing. Ultimately, this is exactly why playing the piano is so essential to my personal growth.",chunks:[{text:"When it comes to hobbies, I firmly believe that ",type:"hook"},{text:"tickling the ivories ",type:"native"},{text:"is the most wonderful thing in my life. ",type:"normal"},{text:"To begin with, ",type:"connector"},{text:"playing classical music helps me ",type:"normal"},{text:"find my inner peace ",type:"native"},{text:"and relax my mind after a busy day. ",type:"normal"},{text:"Furthermore, ",type:"connector"},{text:"it takes a lot of patience. ",type:"normal"},{text:"For instance, ",type:"connector"},{text:"whenever I try to ",type:"normal"},{text:"get the hang of ",type:"native"},{text:"a difficult piece, I have to practice it ",type:"normal"},{text:"over and over again. ",type:"native"},{text:"This trains my focus. When I finally play it perfectly, the sense of achievement is simply ",type:"normal"},{text:"mind-blowing. ",type:"native"},{text:"Ultimately, this is exactly why ",type:"hook"},{text:"playing the piano is so essential to my personal growth.",type:"normal"}],explanations:{"tickling the ivories ":{tag:"地道表达",zh:"弹钢琴（ivory 指象牙，代指钢琴琴键），比 play the piano 更具画面感。"},"find my inner peace ":{tag:"高分短语",zh:"寻找内心的平静。"},"get the hang of ":{tag:"俚语/地道",zh:"掌握...的窍门，弄懂如何做某事。"},"over and over again. ":{tag:"地道表达",zh:"一遍又一遍地（强调重复练习的过程）。"},"mind-blowing. ":{tag:"高级形容词",zh:"令人震撼的，极好的（形容成就感非常强烈）。"}},audioQuiz:[{audio:"tickling the ivories",ans:1,options:["吹奏乐器","弹钢琴","听古典乐","买象牙"]},{audio:"get the hang of",ans:0,options:["掌握窍门","放弃练习","悬挂起来","感到无聊"]},{audio:"mind-blowing",ans:2,options:["头脑发热","刮大风","令人震撼的","失去理智"]},{audio:"inner peace",ans:3,options:["室内安静","世界和平","内部零件","内心的平静"]},{audio:"over and over again",ans:0,options:["一遍又一遍","结束了","翻来覆去","到处都是"]}],quickFire:[{zh:"弹钢琴（敲击琴键）",ans:1,options:["Play keys","Tickling the ivories","Making music","Finding peace"]},{zh:"掌握窍门/弄懂",ans:2,options:["Understand it","Know how","Get the hang of","Over and over"]},{zh:"令人震撼的/极好的",ans:0,options:["Mind-blowing","Very good","Inner peace","Tickling"]},{zh:"内心的平静",ans:3,options:["Quiet room","Relax mind","Peaceful","Inner peace"]},{zh:"一遍又一遍",ans:1,options:["Many times","Over and over again","Always doing","Get the hang"]}],mindMap:[{phase:"P",title:"Point 观点",zh:"最爱弹钢琴",zhSub:"生命中最美好的事",en:"When it comes to hobbies, I firmly believe that tickling the ivories is the most wonderful thing...",highlight:["tickling the ivories"]},{phase:"E",title:"Explain 解释",zh:"放松心灵",zhSub:"寻找内心的平静",en:"To begin with, playing classical music helps me find my inner peace and relax my mind...",highlight:["find my inner peace"]},{phase:"A",title:"Analysis 分析",zh:"培养耐心与专注",zhSub:"一遍遍练习掌握难曲",en:"Furthermore, it takes a lot of patience... whenever I try to get the hang of a difficult piece, I practice it over and over again.",highlight:["get the hang of","over and over again"]},{phase:"C",title:"Conclusion 总结",zh:"成就感爆棚，助我成长",zhSub:"对个人成长至关重要",en:"When I finally play it perfectly, the sense of achievement is simply mind-blowing. Ultimately...",highlight:["mind-blowing"]}]},painting:{id:"painting",title:"Painting",icon:"fa-palette",color:"from-pink-500 to-rose-600",fullText:"When it comes to hobbies, I firmly believe that painting is my ultimate favorite. To begin with, it allows me to let my imagination run wild. I can mix different colors to draw my dream world. Besides that, painting is a great way to tune out the noise of daily life. For example, when I sit quietly with my brush for hours, I enter a state of complete focus and feel totally in my element. It is so satisfying to see a blank canvas turn into a beautiful masterpiece. Ultimately, this is exactly why painting brings me so much joy and peace.",chunks:[{text:"When it comes to hobbies, I firmly believe that ",type:"hook"},{text:"painting is my ultimate favorite. ",type:"normal"},{text:"To begin with, ",type:"connector"},{text:"it allows me to ",type:"normal"},{text:"let my imagination run wild. ",type:"native"},{text:"I can mix different colors to draw my dream world. ",type:"normal"},{text:"Besides that, ",type:"connector"},{text:"painting is a great way to ",type:"normal"},{text:"tune out the noise ",type:"native"},{text:"of daily life. ",type:"normal"},{text:"For example, ",type:"connector"},{text:"when I sit quietly with my brush for hours, I enter a state of complete focus and feel totally ",type:"normal"},{text:"in my element. ",type:"native"},{text:"It is so satisfying to see a ",type:"normal"},{text:"blank canvas ",type:"native"},{text:"turn into a beautiful ",type:"normal"},{text:"masterpiece. ",type:"native"},{text:"Ultimately, this is exactly why ",type:"hook"},{text:"painting brings me so much joy and peace.",type:"normal"}],explanations:{"let my imagination run wild. ":{tag:"地道表达",zh:"让想象力自由驰骋，天马行空。"},"tune out the noise ":{tag:"高级动词短语",zh:"屏蔽外界的喧嚣，不理会噪音。"},"in my element. ":{tag:"俚语/地道",zh:"如鱼得水，处于得心应手的状态。"},"blank canvas ":{tag:"名词搭配",zh:"空白画布（常用来比喻充满无限可能）。"},"masterpiece. ":{tag:"高级名词",zh:"杰作，代表作。"}},audioQuiz:[{audio:"let my imagination run wild",ans:0,options:["让想象力驰骋","在野外跑步","变得疯狂","画野生动物"]},{audio:"tune out the noise",ans:2,options:["调高音量","制作噪音","屏蔽喧嚣","听音乐"]},{audio:"in my element",ans:1,options:["在元素周期表里","如鱼得水","感到困惑","在画室里"]},{audio:"masterpiece",ans:3,options:["主要画作","主人","一小块","杰作"]},{audio:"blank canvas",ans:0,options:["空白画布","黑色帐篷","空头支票","油画颜料"]}],quickFire:[{zh:"让想象力自由驰骋",ans:2,options:["Think wildly","Draw my dream","Let my imagination run wild","In my element"]},{zh:"屏蔽喧嚣",ans:1,options:["Close the door","Tune out the noise","Keep quiet","Blank canvas"]},{zh:"如鱼得水/得心应手",ans:3,options:["Like a fish","Masterpiece","Tune out","In my element"]},{zh:"空白画布",ans:0,options:["Blank canvas","White paper","Masterpiece","Empty drawing"]},{zh:"杰作",ans:2,options:["Good painting","Best work","Masterpiece","Blank canvas"]}],mindMap:[{phase:"P",title:"Point 观点",zh:"最爱画画",zhSub:"最终极的爱好",en:"When it comes to hobbies, I firmly believe that painting is my ultimate favorite.",highlight:["ultimate favorite"]},{phase:"E",title:"Explain 解释",zh:"表达自我",zhSub:"让想象力自由驰骋",en:"To begin with, it allows me to let my imagination run wild. I can mix colors...",highlight:["let my imagination run wild"]},{phase:"A",title:"Analysis 分析",zh:"专注与宁静",zhSub:"屏蔽喧嚣，如鱼得水",en:"Besides that, painting is a great way to tune out the noise... enter a state of focus and feel totally in my element.",highlight:["tune out the noise","in my element"]},{phase:"C",title:"Conclusion 总结",zh:"创造杰作的满足感",zhSub:"带来欢乐与平静",en:"It is so satisfying to see a blank canvas turn into a beautiful masterpiece. Ultimately...",highlight:["blank canvas","masterpiece"]}]}}),e("t",[{id:1,title:"高分句型 ①：Whenever 引导的让步状语从句",explanation:"使用 whenever (每当...时) 来描述一个经常发生的场景，比单纯用 when 更加强调动作的规律性和情感的投入，让举例更生动。",sourceSentence:"For instance, whenever we win a tough match by passing the ball selflessly, I feel absolutely on top of the world.",examples:[{en:"Whenever I try to get the hang of a difficult piano piece, I have to practice it over and over again.",zh:"每当我试图掌握一首困难的钢琴曲时，我都必须一遍又一遍地练习。",subj:"I",pred:"try"},{en:"Whenever I feel stressed, taking a walk in the park always helps me calm down.",zh:"每当感到压力大时，去公园散步总能帮我平静下来。",subj:"I",pred:"feel"}]},{id:2,title:"使役动词升级 ②：Keep/Help + sb + do/adj",explanation:'不要总说 "It is good for me"。使用 keep me fit (保持健康) 或 help me blow off steam (帮我缓解压力) 这种「动词+宾语+补语」的结构，显得语言地道且有力量。',sourceSentence:"To begin with, breaking a sweat on the court keeps me fit and helps me blow off steam after a long day.",examples:[{en:"Playing classical music helps me find my inner peace and relax my mind.",zh:"弹奏古典音乐帮助我寻找内心的平静并放松大脑。",subj:"Playing classical music",pred:"helps"},{en:"Reading books every day keeps my brain active and broadens my horizons.",zh:"每天读书让我的大脑保持活跃并拓宽了我的视野。",subj:"Reading books",pred:"keeps"}]},{id:3,title:"万能描述结构 ③：It allows sb to do...",explanation:'在阐述某项爱好的好处时，"It allows me to..." (它允许/让我能够...) 是一个极其高级且百搭的起手式，比 "I can..." 要正式得多。',sourceSentence:"To begin with, it allows me to let my imagination run wild.",examples:[{en:"Learning English allows me to communicate effectively with people from all over the world.",zh:"学习英语让我能够与来自世界各地的人有效沟通。",subj:"It",pred:"allows"},{en:"This teamwork experience allows us to have each other's backs in difficult times.",zh:"这次团队合作的经历让我们能够在困难时期互相支持。",subj:"This experience",pred:"allows"}]}])}}});